import mysql.connector
import os
import re


def validate_file_path(file_path: str) -> str:
    """
    Validate and sanitize the file path to prevent path traversal
    and other security issues.
    """
    # Normalize the path to resolve any '..' or '.' components
    normalized_path = os.path.normpath(file_path)
    
    # Define allowed base directory for imports
    ALLOWED_BASE_DIR = os.path.normpath("/var/data/imports")
    
    # Resolve to absolute path
    absolute_path = os.path.abspath(normalized_path)
    
    # Ensure the resolved path is within the allowed directory
    if not absolute_path.startswith(ALLOWED_BASE_DIR + os.sep) and absolute_path != ALLOWED_BASE_DIR:
        raise ValueError(
            f"Access denied: File path must be within {ALLOWED_BASE_DIR}. "
            f"Resolved path: {absolute_path}"
        )
    
    # Check that the file actually exists
    if not os.path.isfile(absolute_path):
        raise FileNotFoundError(f"File not found: {absolute_path}")
    
    # Check that it's a regular file (not a symlink to outside allowed dir)
    real_path = os.path.realpath(absolute_path)
    if not real_path.startswith(ALLOWED_BASE_DIR + os.sep):
        raise ValueError(
            f"Access denied: Symlink target must be within {ALLOWED_BASE_DIR}. "
            f"Real path: {real_path}"
        )
    
    # Only allow specific file extensions
    ALLOWED_EXTENSIONS = {'.csv', '.tsv', '.txt', '.dat'}
    _, ext = os.path.splitext(absolute_path)
    if ext.lower() not in ALLOWED_EXTENSIONS:
        raise ValueError(
            f"Invalid file extension '{ext}'. Allowed: {ALLOWED_EXTENSIONS}"
        )
    
    return absolute_path


def validate_table_name(table_name: str) -> str:
    """
    Validate table name to prevent SQL injection.
    Only allow alphanumeric characters and underscores.
    """
    if not table_name:
        raise ValueError("Table name cannot be empty.")
    
    # Whitelist: only allow alphanumeric and underscores
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', table_name):
        raise ValueError(
            f"Invalid table name '{table_name}'. "
            "Only alphanumeric characters and underscores are allowed, "
            "and it must start with a letter or underscore."
        )
    
    # Check against a maximum length
    if len(table_name) > 64:
        raise ValueError("Table name exceeds maximum length of 64 characters.")
    
    # Optionally, whitelist allowed table names for the ETL pipeline
    ALLOWED_TABLES = {
        'customers', 'orders', 'products', 'transactions',
        'inventory', 'sales_data', 'user_events', 'staging_data'
    }
    
    if table_name.lower() not in ALLOWED_TABLES:
        raise ValueError(
            f"Table '{table_name}' is not in the allowed tables list. "
            f"Allowed tables: {ALLOWED_TABLES}"
        )
    
    return table_name


def get_db_connection():
    """
    Create a MySQL connection with local_infile enabled.
    Credentials should come from environment variables or a secrets manager.
    """
    connection = mysql.connector.connect(
        host=os.environ.get('MYSQL_HOST', 'localhost'),
        port=int(os.environ.get('MYSQL_PORT', 3306)),
        user=os.environ.get('MYSQL_USER'),
        password=os.environ.get('MYSQL_PASSWORD'),
        database=os.environ.get('MYSQL_DATABASE'),
        allow_local_infile=True
    )
    return connection


def bulk_import(file_path: str, table_name: str, field_delimiter: str = ',',
                line_terminator: str = r'\n', skip_header_lines: int = 1):
    """
    Perform a bulk import using LOAD DATA LOCAL INFILE with parameterized
    and validated inputs to prevent SQL injection and path traversal.
    """
    # Validate inputs
    safe_file_path = validate_file_path(file_path)
    safe_table_name = validate_table_name(table_name)
    
    # Validate delimiter - only allow known safe delimiters
    ALLOWED_DELIMITERS = {',', '\t', '|', ';'}
    if field_delimiter not in ALLOWED_DELIMITERS:
        raise ValueError(
            f"Invalid delimiter '{field_delimiter}'. Allowed: {ALLOWED_DELIMITERS}"
        )
    
    # Validate line terminator
    ALLOWED_LINE_TERMINATORS = {r'\n', r'\r\n', r'\r'}
    if line_terminator not in ALLOWED_LINE_TERMINATORS:
        raise ValueError(
            f"Invalid line terminator. Allowed: {ALLOWED_LINE_TERMINATORS}"
        )
    
    # Validate skip_header_lines
    if not isinstance(skip_header_lines, int) or skip_header_lines < 0:
        raise ValueError("skip_header_lines must be a non-negative integer.")
    
    connection = None
    cursor = None
    
    try:
        connection = get_db_connection()
        cursor = connection.cursor()
        
        # Build the query safely using validated/whitelisted components.
        # Table name is whitelisted against a known set, so backtick-quoting
        # is a defense-in-depth measure, not the primary protection.
        # File path is validated to be within an allowed directory.
        # Delimiters and terminators are whitelisted.
        query = (
            f"LOAD DATA LOCAL INFILE %s "
            f"INTO TABLE `{safe_table_name}` "
            f"FIELDS TERMINATED BY %s "
            f"ENCLOSED BY '\"' "
            f"LINES TERMINATED BY %s "
            f"IGNORE %s LINES"
        )
        
        # Note: MySQL's LOAD DATA INFILE doesn't support full parameterization
        # for all clauses. The file path can be passed as a parameter with
        # some connectors. Since we've thoroughly validated all inputs above,
        # we construct the query string safely.
        
        # For mysql.connector, LOAD DATA LOCAL INFILE requires the file path
        # in the SQL string directly. We use our validated path.
        query = (
            f"LOAD DATA LOCAL INFILE '{safe_file_path}' "
            f"INTO TABLE `{safe_table_name}` "
            f"FIELDS TERMINATED BY '{field_delimiter}' "
            f"ENCLOSED BY '\"' "
            f"LINES TERMINATED BY '{line_terminator}' "
            f"IGNORE {skip_header_lines} LINES"
        )
        
        print(f"Executing bulk import:")
        print(f"  File: {safe_file_path}")
        print(f"  Table: {safe_table_name}")
        print(f"  Delimiter: {repr(field_delimiter)}")
        print(f"  Skip lines: {skip_header_lines}")
        
        cursor.execute(query)
        connection.commit()
        
        rows_affected = cursor.rowcount
        warnings = cursor.fetchwarnings() if hasattr(cursor, 'fetchwarnings') else []
        
        print(f"  Rows imported: {rows_affected}")
        if warnings:
            print(f"  Warnings: {warnings}")
        
        return rows_affected
        
    except mysql.connector.Error as e:
        print(f"MySQL Error: {e}")
        if connection:
            connection.rollback()
        raise
    except Exception as e:
        print(f"Error during bulk import: {e}")
        if connection:
            connection.rollback()
        raise
    finally:
        if cursor:
            cursor.close()
        if connection:
            connection.close()


